"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[762545],{285592:e=>{e.exports=JSON.parse('{"tag":{"label":"trap","permalink":"/dst-api-webdocs/docs/tags/trap","allTagsPath":"/dst-api-webdocs/docs/tags","count":35,"items":[{"id":"game-scripts/prefabs/alterguardian_phase3trap","title":"Alterguardian Phase3Trap","description":"Manages the lifecycle, behavior, and effects of the Alterguardian\'s Phase 3 meteor trap, including landing damage, grogginess pulses, and trap destruction/loot handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardian_phase3trap"},{"id":"game-scripts/components/bait","title":"Bait","description":"Manages bait behavior for traps, handling attachment to and detachment from trap entities via lifecycle events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bait"},{"id":"game-scripts/prefabs/beemine","title":"Beemine","description":"A deployable trap that rattles when armed, explodes upon triggering, and spawns a swarm of bees toward a nearby valid target.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beemine"},{"id":"game-scripts/prefabs/birdtrap","title":"Birdtrap","description":"A portable trap prefab that captures birds when baited and sprung, supporting multiple bird species with symbol swaps and finite uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birdtrap"},{"id":"game-scripts/scenarios/chest_abandonedboat","title":"Chest Abandonedboat","description":"Sets up loot and trap logic for an abandoned boat chest, including randomized item generation and a 90% chance to trigger a pirate or ghost attack on opening.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_abandonedboat"},{"id":"game-scripts/scenarios/chest_bees","title":"Chest Bees","description":"Manages the initialization and behavior of a beehive trap chest that spawns bees when opened and regulates bee spawning based on time of day and season.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_bees"},{"id":"game-scripts/scenarios/chest_explosion","title":"Chest Explosion","description":"Sets up a chest prefab to explode upon interaction, dropping a predefined set of loot items and registering a trap trigger function.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_explosion"},{"id":"game-scripts/scenarios/chest_foodspoil","title":"Chest Foodspoil","description":"Implements a chest trap that spoils food items in the player\'s inventory and equipped gear when opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_foodspoil"},{"id":"game-scripts/scenarios/chest_ghosts","title":"Chest Ghosts","description":"A scenario script that modifies chest behavior to spawn ghosts and drain sanity when opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_ghosts"},{"id":"game-scripts/scenarios/chest_insanity","title":"Chest Insanity","description":"Handles the logic for spawning sanity-based trap rocks when an \\"insanity chest\\" is opened, using the chest trap framework.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_insanity"},{"id":"game-scripts/scenarios/chest_labyrinth","title":"Chest Labyrinth","description":"Defines lifecycle callbacks for labyrinth-themed chests that generate randomized loot and associate random trap behaviors upon opening.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_labyrinth"},{"id":"game-scripts/scenarios/chest_summer","title":"Chest Summer","description":"Provides loot rewards and triggers seasonal changes when a summer-themed chest is opened in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_summer"},{"id":"game-scripts/scenarios/chest_terrarium","title":"Chest Terrarium","description":"Generates loot for a terrarium chest and initializes its trap system during chest creation and loading.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_terrarium"},{"id":"game-scripts/scenarios/chest_terrarium_fire","title":"Chest Terrarium Fire","description":"Triggers ignition of nearby evil flowers when the terrarium chest is opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_terrarium_fire"},{"id":"game-scripts/scenarios/chest_terrarium_pigs","title":"Chest Terrarium Pigs","description":"Triggers a trap when a specific chest is opened, transforming nearby pigs into werepigs and setting them to attack the triggering player.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_terrarium_pigs"},{"id":"game-scripts/scenarios/chest_winter","title":"Chest Winter","description":"Defines the behavior and loot distribution for a winter-themed chest that triggers seasonal changes when opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_winter"},{"id":"game-scripts/scenarios/chestfunctions","title":"Chestfunctions","description":"Provides utility functions for spawning loot in containers and managing chest trap behaviors with randomization and event handling.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chestfunctions"},{"id":"game-scripts/scenarios/icebox_summer","title":"Icebox Summer","description":"Handles seasonal trap logic and loot setup for a special ice-themed chest that triggers summer season upon opening.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/icebox_summer"},{"id":"game-scripts/prefabs/ivy_snare","title":"Ivy Snare","description":"A trap-like prefab that spawns, targets a nearby enemy, and deals periodic damage before deactivating after death.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ivy_snare"},{"id":"game-scripts/scenarios/magic_pumpkin","title":"Magic Pumpkin","description":"A scenario-triggered trap that triggers when a pumpkin carver is picked up, growing the pumpkin into an oversized state and spawning crows and a shadow effect.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/magic_pumpkin"},{"id":"game-scripts/components/mine","title":"Mine","description":"Triggers an explosion effect when a valid nearby entity enters its detection radius, commonly used for traps.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mine"},{"id":"game-scripts/prefabs/quagmire_crabtrap","title":"Quagmire Crabtrap","description":"A reusable trap prefab used in the Quagmire that detects and interacts with passing entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_crabtrap"},{"id":"game-scripts/stategraphs/SGshadow_trap","title":"Sgshadow Trap","description":"Manages the animation, sound, and state transitions for the Shadow Trap entity during spawning, idling, activation, and dispelling phases.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGshadow_trap"},{"id":"game-scripts/stategraphs/SGtrap","title":"Sgtrap","description":"Manages the visual and behavioral states of a trap entity, including idle, sprung, full (with loot), and empty states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGtrap"},{"id":"game-scripts/prefabs/shadow_trap","title":"Shadow Trap","description":"A trap prefab that detects nearby panic-capable targets, triggers a shockwave effect, and applies a movement speed penalty and panic state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_trap"},{"id":"game-scripts/scenarios/staff_hounds","title":"Staff Hounds","description":"Manages a scenario-based trap that springs when an item is placed in an inventory, instantly hibernating nearby hounds and releasing them upon pickup.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/staff_hounds"},{"id":"game-scripts/components/trap","title":"Trap","description":"Manages trap logic including setting, baiting, springing, harvesting, and loot generation for traps in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/trap"},{"id":"game-scripts/prefabs/trap","title":"Trap","description":"Manages trap functionality, including bait detection, capture logic, and finite-usage tracking for mechanical traps in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap"},{"id":"game-scripts/prefabs/trap_bramble","title":"Trap Bramble","description":"A reusable trap prefab that deals damage to enemies on contact, deactivates when sprung, and supports hauntable interaction with special refund mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap_bramble"},{"id":"game-scripts/map/static_layouts/trap_firestaff","title":"Trap Firestaff","description":"Defines a static world map layout for a trap event that spawns a firestaff and multiple fire hounds.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/trap_firestaff"},{"id":"game-scripts/map/static_layouts/trap_icestaff","title":"Trap Icestaff","description":"A static map layout defining spawn positions for an ice staff and multiple ice hounds in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/trap_icestaff"},{"id":"game-scripts/map/static_layouts/trap_sleepingspider","title":"Trap Sleepingspider","description":"Defines a Tiled map layout for the sleeping spider ambush trap, containing spawn positions for the spider and decorative world objects.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/trap_sleepingspider"},{"id":"game-scripts/prefabs/trap_starfish","title":"Trap Starfish","description":"A deployable trap prefab that detains and damages entities upon stepping on it, then resets after a delay; functions as a mine with custom trigger logic and AOE attack.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap_starfish"},{"id":"game-scripts/prefabs/trap_teeth","title":"Trap Teeth","description":"A deployable mine trap that springs on entity contact, deals damage, and consumes one use per trigger.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap_teeth"},{"id":"game-scripts/prefabs/trap_vines","title":"Trap Vines","description":"A deployable trap entity that detects moving targets within its radius, applies a movement speed debuff, and deals damage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap_vines"}],"unlisted":false}}')}}]);